#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
ll n,m;
int main(void)
{
    n=read(),m=read();
    vector<ll> a(n+2,0),b(m+1),s(5e6+4,0);
	for(int i=1;i<=n;++i)
	{
	    a[i]=read();
    }
	for(int i=1;i<=m;++i)
    {
		b[i]=read();
		s[b[i]]=1;
	}
	int f=0,ans=0;
	for(int i=0;i<=n;++i)
    {
		if(s[a[i]])
        {
            a[i]=0;
        }
		if(s[a[i+1]])
        {
            a[i+1]=0;
        }
		if(a[i]==0&&a[i+1]!=0)
		{
		    f=1;
        }
		if(f&&a[i]!=0&&a[i+1]==0)
        {
			++ans;
            f=0;
		}
	}
	write(ans);
	return false;
}
